__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row = blockIdx.y * 32 + threadIdx.y;
    int col = blockIdx.x * 32 + threadIdx.x;
    int tid = threadIdx.y * 32 + threadIdx.x;
    int block_row = blockIdx.y * 32;
    int block_col = blockIdx.x * 32;
    __shared__ float As[544];
    __shared__ float Bs[528];
    float acc = 0.0f;
    for (int tile_k = 0; tile_k < K; tile_k += 16) {
        for (int i = tid; i < 512; i += 1024) {
            int a_r = i / 16;
            int a_c = i % 16;
            As[a_r * 17 + a_c] = ((block_row + a_r < M && tile_k + a_c < K) ? (A[(block_row + a_r) * K + (tile_k + a_c)]) : (0.0f));
        }
        for (int j = tid; j < 512; j += 1024) {
            int b_r = j / 32;
            int b_c = j % 32;
            Bs[b_r * 33 + b_c] = ((tile_k + b_r < K && block_col + b_c < N) ? (B[(tile_k + b_r) * N + (block_col + b_c)]) : (0.0f));
        }
        __syncthreads();
        for (int kk = 0; kk < 16; kk++) {
            acc += As[threadIdx.y * 17 + kk] * Bs[kk * 33 + threadIdx.x];
        }
        __syncthreads();
    }
    if (row < M && col < N) {
        C[row * N + col] = acc;
    }
}
